/**
 * Cooee SDK — Stealth Mode
 * TRACKING ONLY. Zero UI. Zero DOM changes. Zero CLS/TBT/LCP impact.
 * Just records: who visited, what they did, their intent score, cart data.
 * Version: 3.2.0-stealth
 */
(function (window, document) {
  "use strict";

  var COOEE_VERSION = "3.2.0-stealth";

  var config = { appId: null, apiBase: "", debugMode: false, syncInterval: 15000 };

  var visitor = {
    id: null, fingerprintId: null, confidence: 0,
    sessionId: null, isReturning: false, visitCount: 0, firstSeenAt: null,
    intent: "low", intentScore: 0,
    pageViews: 0, timeOnSite: 0, scrollDepth: 0, clickCount: 0,
    cartItems: 0, cartValue: 0,
    source: "direct",
    device: /Mobi|Android/i.test(navigator.userAgent) ? "mobile" : "desktop",
    entryPage: window.location.pathname,
    currentPage: window.location.pathname,
    pages: [window.location.pathname],
    email: null, phone: null,
    isLoggedIn: false, shopifyCustomer: null,
  };

  var state = { initialized: false, fingerprintReady: false, pendingEvents: [] };

  // ─── Utils ───
  function generateId() { return "c_" + Math.random().toString(36).substr(2, 9) + Date.now().toString(36); }
  function log() { if (config.debugMode) console.log.apply(console, ["[Cooee Stealth]"].concat(Array.prototype.slice.call(arguments))); }

  function detectSource() {
    var ref = document.referrer;
    if (!ref) return "direct";
    var params = new URLSearchParams(window.location.search);
    if (params.get("utm_source")) return params.get("utm_source");
    if (params.get("gclid")) return "google_ads";
    if (params.get("fbclid")) return "meta_ads";
    if (ref.includes("google")) return "google_organic";
    if (ref.includes("facebook") || ref.includes("fb.com")) return "meta_ads";
    if (ref.includes("instagram")) return "instagram";
    if (ref.includes("whatsapp") || ref.includes("wa.me")) return "whatsapp";
    if (ref.includes("youtube")) return "youtube";
    if (ref.includes("twitter") || ref.includes("x.com")) return "twitter";
    return ref.replace(/https?:\/\/(www\.)?/, "").split("/")[0];
  }

  // ─── FingerprintJS ───
  function loadFingerprintJS() {
    return new Promise(function (resolve) {
      if (window.FingerprintJS) { resolve(window.FingerprintJS); return; }
      var s = document.createElement("script");
      s.src = "https://openfpcdn.io/fingerprintjs/v4/iife.min.js";
      s.async = true;
      s.onload = function () { resolve(window.FingerprintJS || null); };
      s.onerror = function () { resolve(null); };
      document.head.appendChild(s);
    });
  }

  function canvasFingerprint() {
    try {
      var c = document.createElement("canvas"); c.width = 200; c.height = 50;
      var ctx = c.getContext("2d"); ctx.textBaseline = "top"; ctx.font = "14px Arial";
      ctx.fillStyle = "#f60"; ctx.fillRect(40, 0, 62, 20);
      ctx.fillStyle = "#069"; ctx.fillText("Cooee", 2, 15);
      return c.toDataURL().slice(-50);
    } catch (e) { return "no-canvas"; }
  }

  function fallbackFingerprint() {
    var signals = [navigator.userAgent, navigator.language, screen.width + "x" + screen.height,
      screen.colorDepth, new Date().getTimezoneOffset(), navigator.hardwareConcurrency || "?",
      navigator.platform, canvasFingerprint()].join("|");
    var hash = 0;
    for (var i = 0; i < signals.length; i++) { hash = ((hash << 5) - hash) + signals.charCodeAt(i); hash |= 0; }
    return "c_fb_" + Math.abs(hash).toString(36);
  }

  async function getFingerprint() {
    try {
      var FP = await loadFingerprintJS();
      if (FP) {
        var fp = await FP.load();
        var result = await fp.get();
        visitor.fingerprintId = result.visitorId;
        visitor.confidence = result.confidence.score;
        log("Fingerprint:", result.visitorId, "Confidence:", (result.confidence.score * 100).toFixed(1) + "%");
        return result.visitorId;
      }
    } catch (e) { log("FP error:", e.message); }
    var fb = fallbackFingerprint();
    visitor.fingerprintId = fb; visitor.confidence = 0.6;
    log("Fallback fingerprint:", fb);
    return fb;
  }

  // ─── Visitor Init ───
  async function initVisitor() {
    var fpId = await getFingerprint();
    var stored = null;
    try { stored = JSON.parse(localStorage.getItem("cooee_fp_" + fpId)); } catch (e) {}

    if (stored && stored.id) {
      visitor.id = stored.id;
      visitor.isReturning = true;
      visitor.visitCount = (stored.visitCount || 0) + 1;
      visitor.firstSeenAt = stored.firstSeenAt;
      visitor.pageViews = stored.pageViews || 0;
      visitor.pages = stored.pages || [];
      log("Returning visitor #" + visitor.visitCount);
    } else {
      visitor.id = "c_" + fpId;
      visitor.isReturning = false;
      visitor.visitCount = 1;
      visitor.firstSeenAt = Date.now();
      log("New visitor:", visitor.id);
    }

    visitor.sessionId = generateId();
    visitor.pageViews++;
    visitor.source = detectSource();
    if (!visitor.pages.includes(window.location.pathname)) visitor.pages.push(window.location.pathname);
    saveLocal();

    state.fingerprintReady = true;
    state.pendingEvents.forEach(function (pe) { sendEvent(pe.event, pe.data); });
    state.pendingEvents = [];
  }

  function saveLocal() {
    try {
      var key = visitor.fingerprintId ? "cooee_fp_" + visitor.fingerprintId : "cooee_visitor";
      localStorage.setItem(key, JSON.stringify({
        id: visitor.id, fingerprintId: visitor.fingerprintId,
        pageViews: visitor.pageViews, pages: visitor.pages,
        visitCount: visitor.visitCount, firstSeenAt: visitor.firstSeenAt,
      }));
    } catch (e) {}
  }

  // ─── Intent ───
  function calculateIntent() {
    var score = 0;
    score += Math.min(visitor.timeOnSite / 12, 25);
    score += Math.min(visitor.pageViews * 5, 20);
    score += (visitor.scrollDepth / 100) * 15;
    score += Math.min(visitor.clickCount * 2, 15);
    if (visitor.cartItems > 0) score += 15;
    if (visitor.cartValue > 500) score += 10;

    var prev = visitor.intent;
    visitor.intentScore = Math.round(score);
    if (score >= 60) visitor.intent = "high";
    else if (score >= 30) visitor.intent = "medium";
    else visitor.intent = "low";

    if (visitor.intent !== prev) {
      log("Intent:", prev, "→", visitor.intent, "(score:" + visitor.intentScore + ")");
      sendEvent("intent_changed", { from: prev, to: visitor.intent, score: visitor.intentScore });
    }
  }

  // ─── Tracking (passive, debounced) ───
  function trackScroll() {
    var max = 0, timer = null;
    window.addEventListener("scroll", function () {
      if (timer) return;
      timer = setTimeout(function () {
        timer = null;
        var h = document.documentElement.scrollHeight - window.innerHeight;
        if (h <= 0) return;
        var pct = Math.round((window.scrollY / h) * 100);
        if (pct > max) { max = pct; visitor.scrollDepth = max; calculateIntent(); }
      }, 250);
    }, { passive: true });
  }

  function trackClicks() {
    document.addEventListener("click", function () {
      visitor.clickCount++;
      calculateIntent();
    }, { passive: true });
  }

  function trackTime() {
    setInterval(function () { visitor.timeOnSite += 5; calculateIntent(); }, 5000);
  }

  function trackNavigation() {
    var lastPath = window.location.pathname;
    var check = function () {
      if (window.location.pathname !== lastPath) {
        lastPath = window.location.pathname;
        visitor.currentPage = lastPath;
        visitor.pageViews++;
        if (!visitor.pages.includes(lastPath)) visitor.pages.push(lastPath);
        saveLocal();
        sendEvent("page_view", { page: lastPath });
        calculateIntent();
      }
    };
    window.addEventListener("popstate", check);
    var origPush = history.pushState;
    history.pushState = function () { origPush.apply(history, arguments); setTimeout(check, 100); };
  }

  // ─── Shopify Cart Detection ───
  function detectCart() {
    function fetchCart() {
      fetch("/cart.js", { credentials: "same-origin" }).then(function (r) { return r.json(); }).then(function (cart) {
        if (cart && typeof cart.item_count === "number") {
          var prev = visitor.cartItems;
          visitor.cartItems = cart.item_count;
          visitor.cartValue = (cart.total_price || 0) / 100;
          calculateIntent();
          if (cart.item_count > prev) {
            sendEvent("cart_updated", { items: cart.item_count, value: visitor.cartValue });
            log("Cart:", cart.item_count, "items, ₹" + visitor.cartValue);
          }
        }
      }).catch(function () {});
    }
    fetchCart();
    var origFetch = window.fetch;
    window.fetch = function () {
      var url = arguments[0];
      if (typeof url === "string" && (url.includes("/cart/add") || url.includes("/cart/change") || url.includes("/cart/update"))) {
        var result = origFetch.apply(this, arguments);
        result.then(function () { setTimeout(fetchCart, 500); });
        return result;
      }
      return origFetch.apply(this, arguments);
    };
  }

  // ─── Shopify Customer Detection ───
  function detectCustomer() {
    try {
      var sources = [window.__customer, window.__st && window.__st.cid ? { id: window.__st.cid } : null,
        window.ShopifyAnalytics && window.ShopifyAnalytics.meta && window.ShopifyAnalytics.meta.page && window.ShopifyAnalytics.meta.page.customerId ? { id: window.ShopifyAnalytics.meta.page.customerId } : null];
      for (var i = 0; i < sources.length; i++) {
        var src = sources[i];
        if (src && (src.id || src.email)) {
          visitor.isLoggedIn = true;
          visitor.email = src.email || null;
          visitor.phone = src.phone || null;
          var orders = src.orders_count || 0;
          var tier = orders >= 10 ? "vip" : orders >= 3 ? "loyal" : orders >= 1 ? "returning" : "new";
          if (orders > 0) { visitor.isReturning = true; visitor.visitCount = Math.max(visitor.visitCount, orders); }
          sendEvent("customer_identified", { shopifyCustomerId: String(src.id), ordersCount: orders, totalSpent: parseFloat(src.total_spent || 0), tier: tier });
          log("Shopify customer:", src.email || src.id, "| Orders:", orders, "| Tier:", tier);
          break;
        }
      }
    } catch (e) {}
  }

  // ─── Shopify E-commerce Events (checkout, purchase, thank you page) ───
  function detectEcommerceEvents() {
    var path = window.location.pathname;

    // Checkout page detection
    if (path.includes("/checkout")) {
      sendEvent("checkout_started", { page: path });
      log("Checkout started");
    }

    // Thank you / order confirmation page (Shopify redirects here after purchase)
    if (path.includes("/thank_you") || path.includes("/orders/") || path.includes("/order-confirmation")) {
      // Try to extract order data from Shopify's global
      var orderData = {};
      try {
        if (window.Shopify && window.Shopify.checkout) {
          var co = window.Shopify.checkout;
          orderData = {
            orderId: co.order_id,
            value: parseFloat(co.total_price || co.payment_due || 0),
            currency: co.currency || "INR",
            items: co.line_items ? co.line_items.length : 0,
            discount: parseFloat(co.total_discounts || 0),
            shipping: parseFloat(co.shipping_rate ? co.shipping_rate.price : 0),
            email: co.email,
            phone: co.phone || (co.billing_address ? co.billing_address.phone : null),
          };
          if (co.email) visitor.email = co.email;
          if (orderData.phone) visitor.phone = orderData.phone;
          visitor.converted = true;
        }
      } catch (e) {}

      sendEvent("purchase", orderData);
      sendEvent("conversion", orderData);
      log("Purchase detected!", orderData);
    }

    // Shopify analytics event listener (works on checkout pages too)
    try {
      if (window.ShopifyAnalytics && window.ShopifyAnalytics.lib) {
        var origTrack = window.ShopifyAnalytics.lib.track;
        if (origTrack) {
          window.ShopifyAnalytics.lib.track = function () {
            var eventName = arguments[0];
            var eventData = arguments[1] || {};
            // Capture Shopify's own checkout events
            if (eventName === "Completed Checkout" || eventName === "Paid") {
              sendEvent("shopify_checkout_completed", eventData);
              visitor.converted = true;
              log("Shopify checkout event:", eventName);
            }
            if (eventName === "Started Checkout") {
              sendEvent("shopify_checkout_started", eventData);
            }
            if (eventName === "Added Product") {
              sendEvent("shopify_product_added", eventData);
            }
            if (eventName === "Viewed Product") {
              sendEvent("shopify_product_viewed", { product: eventData.name || eventData.id });
            }
            return origTrack.apply(this, arguments);
          };
        }
      }
    } catch (e) {}

    // Detect product page views from URL pattern
    if (path.match(/\/products\/[^/]+$/)) {
      sendEvent("product_viewed", { page: path, product: path.split("/products/")[1] });
    }

    // Detect collection/PLP page views
    if (path.match(/\/collections\/[^/]+$/)) {
      sendEvent("collection_viewed", { page: path, collection: path.split("/collections/")[1] });
    }
  }

  // ─── Send to Server ───
  function sendEvent(event, data) {
    if (!config.apiBase) return;
    if (!state.fingerprintReady) { state.pendingEvents.push({ event: event, data: data }); return; }

    var payload = {
      visitorId: visitor.id, sessionId: visitor.sessionId,
      event: event, data: data || {}, page: window.location.pathname,
      visitor: {
        intent: visitor.intent, intentScore: visitor.intentScore,
        pageViews: visitor.pageViews, timeOnSite: visitor.timeOnSite,
        scrollDepth: visitor.scrollDepth, clickCount: visitor.clickCount,
        cartItems: visitor.cartItems, cartValue: visitor.cartValue,
        source: visitor.source, device: visitor.device,
        entryPage: visitor.entryPage, currentPage: visitor.currentPage,
        pages: visitor.pages, email: visitor.email, phone: visitor.phone,
        fingerprintId: visitor.fingerprintId, confidence: visitor.confidence,
        isReturning: visitor.isReturning, visitCount: visitor.visitCount,
        firstSeenAt: visitor.firstSeenAt, isLoggedIn: visitor.isLoggedIn,
      },
    };

    fetch(config.apiBase + "/api/events", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    }).catch(function () {});
  }

  function startSync() {
    setInterval(function () {
      sendEvent("heartbeat", { intentScore: visitor.intentScore, timeOnSite: visitor.timeOnSite, scrollDepth: visitor.scrollDepth });
    }, config.syncInterval);
  }

  // ─── Public API ───
  window.Cooee = {
    version: COOEE_VERSION,
    init: async function (appId, options) {
      if (state.initialized) return;
      state.initialized = true;
      config.appId = appId;
      if (options && options.apiBase) config.apiBase = options.apiBase;
      if (options && options.debug) config.debugMode = true;

      trackScroll(); trackClicks(); trackTime(); trackNavigation();
      detectCart(); detectCustomer(); detectEcommerceEvents();
      await initVisitor();

      sendEvent("page_view", { page: window.location.pathname, isEntry: true, isReturning: visitor.isReturning, visitCount: visitor.visitCount });
      startSync();
      log("Ready. Visitor:", visitor.id, "| Returning:", visitor.isReturning, "| Source:", visitor.source);
    },
    getVisitor: function () { return Object.assign({}, visitor); },
    getIntent: function () { return { level: visitor.intent, score: visitor.intentScore }; },
    getFingerprint: function () { return { id: visitor.fingerprintId, confidence: visitor.confidence, isReturning: visitor.isReturning, visitCount: visitor.visitCount }; },
    setCartData: function (items, value) { visitor.cartItems = items; visitor.cartValue = value; calculateIntent(); sendEvent("cart_updated", { items: items, value: value }); },
    trackEvent: function (event, data) { sendEvent(event, data || {}); },
    debug: function (on) { config.debugMode = on !== false; if (config.debugMode) { console.log("[Cooee Stealth] Visitor:", visitor.id, "| FP:", visitor.fingerprintId, "| Intent:", visitor.intent, "(" + visitor.intentScore + ")", "| Source:", visitor.source, "| Pages:", visitor.pages.join(" → ")); } },
  };

  // ─── Auto-init ───
  var scripts = document.querySelectorAll("script[data-app-id]");
  scripts.forEach(function (s) {
    var appId = s.getAttribute("data-app-id");
    var apiBase = s.getAttribute("data-api-base") || "";
    var debug = s.getAttribute("data-debug") === "true";
    if (appId) window.Cooee.init(appId, { apiBase: apiBase, debug: debug });
  });

})(window, document);
